// Signal Arc -- branching lightning energy from a central grandmaster node.
uniform vec4 uArc;     // x=bolts, y=jaggedness, z=branchiness, w=strikeTime(=absTime*restrikeRate)
uniform vec4 uEnergy;  // x=coreWidth, y=coronaGlow, z=reach, w=filaments
uniform vec4 uClock;   // x=ptpRate, y=syncRing, z=palette, w=absTime
out vec4 fragColor;
const float PI = 3.14159265;

float hash11(float p){ return fract(sin(p*127.1)*43758.5453); }
float hash21(vec2 p){ return fract(sin(dot(p, vec2(127.1,311.7)))*43758.5453); }
float vnoise(vec2 p){
    vec2 i=floor(p), f=fract(p); vec2 u=f*f*(3.0-2.0*f);
    return mix(mix(hash21(i), hash21(i+vec2(1,0)), u.x),
               mix(hash21(i+vec2(0,1)), hash21(i+vec2(1,1)), u.x), u.y);
}

// distance from point p to segment a-b
float segDist(vec2 p, vec2 a, vec2 b){
    vec2 pa=p-a, ba=b-a; float h=clamp(dot(pa,ba)/dot(ba,ba),0.0,1.0); return length(pa-ba*h);
}

// per-bolt essence color: mostly cyan, a few essence channels
vec3 boltColor(float i, float hue){
    float k = mod(i, 9.0);
    vec3 c;
    if(k < 6.0) c = vec3(0.10, 0.85, 1.00);      // cyan signal
    else if(k < 7.0) c = vec3(0.25, 1.00, 0.45);  // green
    else if(k < 8.0) c = vec3(1.00, 0.22, 0.62);  // magenta
    else c = vec3(1.00, 0.70, 0.12);              // amber
    // small hue nudge from palette param
    return mix(c, c.gbr, hue*0.4);
}

void main(){
    vec2 uv = vUV.st;
    float aspect = uTDOutputInfo.res.z / uTDOutputInfo.res.w;
    vec2 p = vec2((uv.x-0.5)*aspect, uv.y-0.5);

    vec3 col = mix(vec3(0.008,0.010,0.014), vec3(0.0,0.0,0.0), length(p));  // deep black ground

    vec2 center = vec2(0.0, 0.0);
    float nB    = clamp(uArc.x, 1.0, 12.0);
    float jag   = uArc.y;
    float branch= uArc.z;
    float strike= uArc.w;
    float cw    = uEnergy.x;
    float corona= uEnergy.y;
    float reach = uEnergy.z;
    float fil   = uEnergy.w;
    float hue   = uClock.z;

    float glowAccum = 0.0;
    vec3  colorAccum = vec3(0.0);

    const int MAXB = 12;     // bolts
    const int SEG  = 14;     // segments per bolt
    for(int b=0; b<MAXB; b++){
        if(float(b) >= nB) break;
        float fb = float(b);
        float ang = (fb/nB)*6.28318 + hash11(fb*5.1)*0.4;
        // re-strike: a new noise phase each PTP-ish strike interval
        float strikeId = floor(strike + hash11(fb*2.3));
        float seed = fb*13.0 + strikeId*7.0;
        // target node out in the field
        vec2 target = center + vec2(cos(ang), sin(ang)) * reach * (0.6 + 0.4*hash11(seed));

        vec2 prev = center;
        vec3 bc = boltColor(fb, hue);
        for(int s=1; s<=SEG; s++){
            float fs = float(s)/float(SEG);
            vec2 base = mix(center, target, fs);
            // jagged displacement perpendicular to the bolt, from noise
            vec2 dir = normalize(target - center + 1e-5);
            vec2 nrm = vec2(-dir.y, dir.x);
            float n = vnoise(vec2(seed, fs*8.0)) - 0.5;
            float disp = n * jag * 0.12 * sin(fs*PI);  // taper to 0 at endpoints
            vec2 cur = base + nrm * disp;

            float d = segDist(p, prev, cur);
            float core = smoothstep(cw, 0.0, d);
            float halo = smoothstep(cw*10.0*corona, 0.0, d) * 0.18;
            float g = core*1.4 + halo;
            glowAccum += g;
            colorAccum += mix(bc, vec3(1.0), core) * g;

            // a fork: spawn a short child branch at a couple of points
            if(branch > 0.5 && (s == 5 || s == 9)){
                float fa = (hash11(seed+fs)*2.0-1.0) * 1.2;
                vec2 fdir = mat2(cos(fa),-sin(fa),sin(fa),cos(fa)) * dir;
                vec2 fend = cur + fdir * reach * 0.25 * branch;
                float fd = segDist(p, cur, fend);
                float fc = smoothstep(cw*0.8, 0.0, fd);
                float fh = smoothstep(cw*7.0*corona, 0.0, fd) * 0.12;
                float fg = fc*1.0 + fh;
                glowAccum += fg;
                colorAccum += mix(bc, vec3(1.0), fc) * fg;
            }
            prev = cur;
        }
    }

    // fine secondary filament fuzz around the bolts
    float fuzz = vnoise(p*40.0 + strike) * vnoise(p*17.0 - strike);
    colorAccum += vec3(0.10,0.6,0.8) * fuzz * fil * 0.15 * smoothstep(0.0, 0.6, glowAccum);

    col += colorAccum;

    // grandmaster node: a bright pulsing core at center
    float beat = fract(uClock.w * uClock.x);
    float nodePulse = 0.6 + 0.4*pow(max(0.0,1.0-beat*4.0),2.0);
    col += vec3(0.6,0.95,1.0) * smoothstep(0.05, 0.0, length(p)) * nodePulse * 2.0;

    // PTP sync ring: an expanding ring of energy on each beat
    float ringR = beat * reach * 1.2;
    float ring = smoothstep(0.02, 0.0, abs(length(p) - ringR)) * (1.0 - beat);
    col += vec3(0.15,0.7,0.9) * ring * uClock.y;

    // electric haze + edge falloff
    col += vec3(0.01,0.02,0.03) * smoothstep(0.7,0.0,length(p));
    col *= mix(1.0, 0.6, smoothstep(0.5, 1.05, length(p)));

    fragColor = vec4(max(col, 0.0), 1.0);
}

// Searing bloom + grain + PTP-synced micro RGB-split flicker.
uniform vec4 uBloom;   // x=strength, y=threshold, z=rgbSplit, w=ptpTime
out vec4 fragColor;
float hash21(vec2 p){ return fract(sin(dot(p, vec2(127.1,311.7)))*43758.5453); }
void main(){
    vec2 uv = vUV.st;
    vec2 texel = uTDOutputInfo.res.xy;
    float beat = fract(uBloom.w);
    float ev = pow(max(0.0, 1.0 - beat*8.0), 4.0);
    float sp = uBloom.z * (0.001 + 0.004*ev);
    vec3 src;
    src.r = texture(sTD2DInputs[0], uv + vec2(sp,0.0)).r;
    src.g = texture(sTD2DInputs[0], uv).g;
    src.b = texture(sTD2DInputs[0], uv - vec2(sp,0.0)).b;
    float thr = uBloom.y;
    vec3 sum = vec3(0.0); float wsum = 0.0;
    const int R = 7;
    for(int x=-R;x<=R;x++){
        for(int y=-R;y<=R;y++){
            vec2 o = vec2(float(x), float(y));
            float w = exp(-dot(o,o)/26.0);
            vec3 s = texture(sTD2DInputs[0], uv + o*texel*2.6).rgb;
            sum += max(s - thr, 0.0) * w;
            wsum += w;
        }
    }
    vec3 col = src + (sum/max(wsum,1e-4)) * uBloom.x;
    col += (hash21(uv*uTDOutputInfo.res.zw + beat*53.0)-0.5) * 0.013;
    fragColor = vec4(col, 1.0);
}
